/**
 * Embeds layout.html into layout-bundle.js for file:// (double-click) viewing.
 * Run after prepare-layout.js: node post/post-template/bundle-layout.js
 */
const fs = require('fs');
const path = require('path');

const layoutPath = path.join(__dirname, 'layout.html');
const outPath = path.join(__dirname, 'layout-bundle.js');
const html = fs.readFileSync(layoutPath, 'utf8');

const output =
	'/* Generated by bundle-layout.js — do not edit */\n' +
	'window.PATRIARCH_POST_LAYOUT = ' +
	JSON.stringify(html) +
	';\n';

fs.writeFileSync(outPath, output, 'utf8');
console.log('Wrote', outPath, '(' + Math.round(output.length / 1024) + ' KB)');
